// Поиск продукта по штрихкоду
export function searchByBarcode(barcode: string): BarcodeProduct | undefined {
  return barcodeDatabase.find(p => p.barcode === barcode);
}

// Поиск продукта по названию (частичное совпадение)
export function searchByName(name: string): BarcodeProduct[] {
  const lowerName = name.toLowerCase();
  return barcodeDatabase.filter(p => p.name.toLowerCase().includes(lowerName));
}

// Получить все продукты из категории
export function getByCategory(category: string): BarcodeProduct[] {
  return barcodeDatabase.filter(p => p.category === category);
}

// Получить все продукты из магазина
export function getByStore(store: string): BarcodeProduct[] {
  return barcodeDatabase.filter(p => p.store === store);
}
